import React, { useState, useEffect } from 'react';

interface LayoutStats {
  effort: number;
  distance: number;
  same_finger_bigrams_pct: number;
  roll_in_pct: number;
  roll_out_pct: number;
  trigram_alt_pct: number;
}

const DesignerPage: React.FC = () => {
  const [textContent, setTextContent] = useState('` 1 2 3 4 5 6 7 8 9 0 - =\nq w e r t y u i o p [ ]\na s d f g h j k l ; \'\nz x c v b n m , . /');
  const [currentLayout, setCurrentLayout] = useState<Record<string, string>>({});
  const [stats, setStats] = useState<LayoutStats | null>(null);
  const [showFingerColors, setShowFingerColors] = useState(true);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Finger color mapping (consistent with KeyboardVisualization)
  const getFingerTextColor = (finger: number) => {
    const textColors = [
      'text-red-600 dark:text-red-400', // LP (0)
      'text-orange-600 dark:text-orange-400', // LR (1)
      'text-yellow-600 dark:text-yellow-400', // LM (2)
      'text-green-600 dark:text-green-400', // LI (3)
      'text-blue-600 dark:text-blue-400', // LT (4)
      'text-blue-700 dark:text-blue-300', // RT (5)
      'text-green-700 dark:text-green-300', // RI (6)
      'text-yellow-700 dark:text-yellow-300', // RM (7)
      'text-orange-700 dark:text-orange-300', // RR (8)
      'text-red-700 dark:text-red-300', // RP (9)
    ];
    return textColors[finger] || 'text-gray-600 dark:text-gray-400';
  };

  // Finger mapping for standard QWERTY positions (consistent with KeyboardVisualization)
  const getFingerForKey = (key: string): number => {
    const fingerMap: { [key: string]: number } = {
      // Number row
      '`': 0, '1': 0, '2': 1, '3': 2, '4': 3, '5': 3, '6': 6, '7': 6, '8': 7, '9': 8, '0': 9, '-': 9, '=': 9,
      // Top row  
      'q': 0, 'w': 1, 'e': 2, 'r': 3, 't': 3, 'y': 6, 'u': 6, 'i': 7, 'o': 8, 'p': 9, '[': 9, ']': 9,
      // Home row
      'a': 0, 's': 1, 'd': 2, 'f': 3, 'g': 3, 'h': 6, 'j': 6, 'k': 7, 'l': 8, ';': 9, "'": 9,
      // Bottom row
      'z': 0, 'x': 1, 'c': 2, 'v': 3, 'b': 3, 'n': 6, 'm': 6, ',': 7, '.': 8, '/': 9
    };
    return fingerMap[key.toLowerCase()] ?? 4;
  };

  // Parse text content into layout object
  const parseTextToLayout = (text: string): Record<string, string> => {
    const lines = text.split('\n');
    const layout: Record<string, string> = {};
    
    const keyPositions = [
      ['`', '1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '='],
      ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']'],
      ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', '\''],
      ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/']
    ];
    
    lines.forEach((line, rowIndex) => {
      if (rowIndex < keyPositions.length) {
        const chars = line.trim().split(/\s+/).filter(char => char);
        const positions = keyPositions[rowIndex];
        
        chars.forEach((char, charIndex) => {
          if (charIndex < positions.length) {
            layout[positions[charIndex]] = char;
          }
        });
      }
    });
    
    return layout;
  };

  // Analyze layout function using advanced cyanophage-based analysis
  const analyzeLayout = async (layout: Record<string, string>) => {
    if (Object.keys(layout).length === 0) return;
    
    setIsAnalyzing(true);
    try {
      const response = await fetch('/api/analyze', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ layout_data: { keys: layout } }),
      });
      
      if (response.ok) {
        const data = await response.json();
        setStats({
          effort: parseFloat(data.effort),
          distance: parseFloat(data.distance),
          same_finger_bigrams_pct: parseFloat(data.same_finger_bigrams_pct),
          roll_in_pct: parseFloat(data.roll_in_pct),
          roll_out_pct: parseFloat(data.roll_out_pct),
          trigram_alt_pct: parseFloat(data.trigram_alt_pct)
        });
      } else {
        // Fallback to mock analysis
        setStats({
          effort: Math.random() * 0.5 + 1.0,
          distance: Math.random() * 0.8 + 0.8,
          same_finger_bigrams_pct: Math.random() * 5 + 1,
          roll_in_pct: Math.random() * 10 + 10,
          roll_out_pct: Math.random() * 8 + 5,
          trigram_alt_pct: Math.random() * 15 + 15
        });
      }
    } catch (error) {
      console.error('Error analyzing layout:', error);
      // Mock stats for demonstration
      setStats({
        effort: Math.random() * 0.5 + 1.0,
        distance: Math.random() * 0.8 + 0.8,
        same_finger_bigrams_pct: Math.random() * 5 + 1,
        roll_in_pct: Math.random() * 10 + 10,
        roll_out_pct: Math.random() * 8 + 5,
        trigram_alt_pct: Math.random() * 15 + 15
      });
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleTextChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setTextContent(e.target.value);
  };

  // Update layout when text changes
  useEffect(() => {
    const layout = parseTextToLayout(textContent);
    setCurrentLayout(layout);
    // Debounce analysis
    const timeoutId = setTimeout(() => {
      analyzeLayout(layout);
    }, 500);
    
    return () => clearTimeout(timeoutId);
  }, [textContent]);

  // Generate text visual with finger colors (consistent with KeyboardVisualization)
  const generateTextVisualWithColors = (layoutKeys: Record<string, string>) => {
    const rows = [
      ['`', '1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '='],
      ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']'],
      ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', '\''],
      ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/']
    ];
    
    return rows.map((row, rowIndex) => (
      <div key={rowIndex} className="text-center">
        {row.map((key, keyIndex) => {
          const char = layoutKeys[key] || key;
          const finger = getFingerForKey(key);
          const textColor = showFingerColors ? getFingerTextColor(finger) : 'text-gray-700 dark:text-gray-300';
          
          return (
            <span 
              key={keyIndex}
              className={`font-mono text-lg font-semibold px-1 ${textColor}`}
              title={`${key.toUpperCase()} → ${char} (Finger ${finger + 1})`}
            >
              {` ${char} `}
            </span>
          );
        })}
      </div>
    ));
  };

  // Get metric color based on value
  const getMetricColor = (value: number | undefined, good: number, bad: number, lowerIsBetter: boolean = true) => {
    if (value === undefined) return 'text-gray-400';
    if (lowerIsBetter) {
      return value <= good ? 'text-green-500' : value >= bad ? 'text-red-500' : 'text-yellow-500';
    } else {
      return value >= good ? 'text-green-500' : value <= bad ? 'text-red-500' : 'text-yellow-500';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
      <div className="max-w-6xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold bg-gradient-to-r from-purple-600 to-blue-600 bg-clip-text text-transparent mb-4">
            Layout Designer
          </h1>
          <p className="text-gray-600 dark:text-gray-300 max-w-2xl mx-auto">
            Edit your keyboard layout as text and see a live preview with finger colors and analysis.
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left Column: Visual Keyboard Preview */}
          <div className="lg:col-span-2 space-y-6">
            {/* Visual Keyboard */}
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-2xl font-bold">Live Preview</h2>
                <button
                  onClick={() => setShowFingerColors(!showFingerColors)}
                  className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                    showFingerColors
                      ? 'bg-purple-600 text-white'
                      : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'
                  }`}
                >
                  {showFingerColors ? 'Hide' : 'Show'} Finger Colors
                </button>
              </div>
              
              {/* Keyboard Layout */}
              <div className="bg-gray-100 dark:bg-gray-800 p-6 rounded-xl shadow-lg max-w-4xl mx-auto">
                <div className="bg-white dark:bg-gray-900 p-4 rounded-lg border">
                  <div className="leading-relaxed space-y-2">
                    {generateTextVisualWithColors(currentLayout)}
                  </div>
                </div>
                
                <div className="mt-6 text-sm text-gray-600 dark:text-gray-400 text-center">
                  Visual representation of your keyboard layout with finger color coding
                </div>
              </div>
            </div>
            
            {/* Text Editor */}
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <h2 className="text-2xl font-bold mb-4">Text Editor</h2>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium mb-2">
                    Edit your keyboard layout (each row on a new line, characters separated by spaces):
                  </label>
                  <textarea
                    value={textContent}
                    onChange={handleTextChange}
                    className="w-full h-32 p-4 font-mono text-lg border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent bg-gray-50 dark:bg-gray-700 resize-none"
                    placeholder="` 1 2 3 4 5 6 7 8 9 0 - =\nq w e r t y u i o p [ ]\na s d f g h j k l ; '\nz x c v b n m , . /"
                  />
                </div>
                <div className="text-sm text-gray-600 dark:text-gray-400">
                  <p><strong>Instructions:</strong></p>
                  <ul className="list-disc list-inside space-y-1">
                    <li>Each line represents a row on the keyboard</li>
                    <li>Characters are separated by spaces</li>
                    <li>Changes are reflected in the visual preview above</li>
                  </ul>
                </div>
              </div>
            </div>
          </div>

          {/* Right Column: Analysis and Legend */}
          <div className="space-y-6">
            {/* Live Analysis */}
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <h3 className="text-xl font-bold mb-4">Live Analysis</h3>
              {isAnalyzing ? (
                <div className="flex items-center justify-center py-8">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-600"></div>
                  <span className="ml-3 text-gray-600 dark:text-gray-400">Analyzing...</span>
                </div>
              ) : stats ? (
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium">Effort</span>
                    <span className={`font-bold ${getMetricColor(stats.effort, 1.2, 1.4)}`}>
                      {stats.effort.toFixed(2)}
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium">Distance</span>
                    <span className={`font-bold ${getMetricColor(stats.distance, 1.0, 1.5)}`}>
                      {stats.distance.toFixed(2)}
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium">Same Finger %</span>
                    <span className={`font-bold ${getMetricColor(stats.same_finger_bigrams_pct, 2, 5)}`}>
                      {stats.same_finger_bigrams_pct.toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium">Roll In %</span>
                    <span className={`font-bold ${getMetricColor(stats.roll_in_pct, 15, 8, false)}`}>
                      {stats.roll_in_pct.toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium">Roll Out %</span>
                    <span className={`font-bold ${getMetricColor(stats.roll_out_pct, 12, 6, false)}`}>
                      {stats.roll_out_pct.toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium">Alternation %</span>
                    <span className={`font-bold ${getMetricColor(stats.trigram_alt_pct, 25, 15, false)}`}>
                      {stats.trigram_alt_pct.toFixed(1)}%
                    </span>
                  </div>
                </div>
              ) : (
                <div className="text-center py-8 text-gray-500 dark:text-gray-400">
                  Start typing to see analysis
                </div>
              )}
            </div>

            {/* Finger Color Legend */}
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <h3 className="text-xl font-bold mb-4">Finger Colors</h3>
              <div className="space-y-2 text-sm">
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-red-200 dark:bg-red-800 border border-gray-300 dark:border-gray-600"></div>
                  <span>LP (Left Pinky)</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-orange-200 dark:bg-orange-800 border border-gray-300 dark:border-gray-600"></div>
                  <span>LR (Left Ring)</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-yellow-200 dark:bg-yellow-800 border border-gray-300 dark:border-gray-600"></div>
                  <span>LM (Left Middle)</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-green-200 dark:bg-green-800 border border-gray-300 dark:border-gray-600"></div>
                  <span>LI (Left Index)</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-blue-200 dark:bg-blue-800 border border-gray-300 dark:border-gray-600"></div>
                  <span>Thumb</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-green-300 dark:bg-green-700 border border-gray-300 dark:border-gray-600"></div>
                  <span>RI (Right Index)</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-4 h-4 rounded bg-yellow-300 dark:bg-yellow-700 border border-gray-300 dark:border-gray-600"></div>
